'use client';

import Link from 'next/link';
import Button from '@/components/ui/Button';
import { useMemo } from 'react';

export default function FlightCard({ flight }) {
  // derivamos la fecha con useMemo
  const formattedDate = useMemo(() => {
    if (!flight.departureTime) return 'Fecha no disponible';
    return new Date(flight.departureTime).toLocaleString('es-ES', {
      day: 'numeric',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  }, [flight.departureTime]);

  // Badge dinámico según estado → usamos clases en lugar de inline styles
  const statusClass =
    flight.status === 'activo'
      ? 'bg-accent text-foreground'
      : flight.status === 'cancelado'
      ? 'bg-buttonText text-foreground'
      : 'bg-yellow-400 text-black';

  return (
    <Link href={`/flights/${flight._id}`} className="block">
      <div className="rounded-lg p-6 shadow-soft hover:shadow-strong transition-all duration-300 bg-surface text-foreground">
        <p className="text-lg font-bold mb-2">
          {flight.code || `${flight.origin}-${flight.destination}`}
        </p>
        <p className="text-sm opacity-80">
          {flight.origin} → {flight.destination}
        </p>
        <p className="text-sm opacity-80">Salida: {formattedDate}</p>

        <span
          className={`inline-block mt-2 px-3 py-1 rounded-full text-xs font-semibold ${statusClass}`}
        >
          Estado: {flight.status}
        </span>

        <div className="mt-4">
          <Button variant="primary" size="sm">
            Ver detalles
          </Button>
        </div>
      </div>
    </Link>
  );
}
