'use client';
import { useState, useEffect, useMemo } from 'react';
import FlightCard from './FlightCard';
import FlightFilters from './FlightFilters';
import Loader from '../ui/Loader';

export default function FlightListClient({
  initialFlights = [],
  initialFilters = {},
  featured = false,
}) {
  const [flights, setFlights] = useState(initialFlights);
  const [filters, setFilters] = useState({
    origin: initialFilters.origin || '',
    destination: initialFilters.destination || '',
  });
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchFlights() {
      setLoading(true);
      setError(null);
      try {
        const query = !featured
          ? new URLSearchParams(
              Object.fromEntries(Object.entries(filters).filter(([, v]) => v))
            ).toString()
          : '';

        const res = await fetch(
          `${process.env.NEXT_PUBLIC_API_BASE_URL}/flights${
            query ? `?${query}` : ''
          }`
        );
        const data = await res.json();

        console.log(
          'Flights from API:',
          data.data.map((f) => ({ id: f.id, status: f.status }))
        );
        setFlights(data.data || []);
        if (!res.ok) {
          setError(data.error || 'Error al cargar vuelos');
          return;
        }
        setFlights(data.data || []);
      } catch {
        setError('Error de conexión con el servidor');
      } finally {
        setLoading(false);
      }
    }

    fetchFlights();
  }, [filters, featured]);

  // derivar lista mostrada
  const filteredFlights = useMemo(() => {
    if (!Array.isArray(flights)) return [];

    if (featured) {
      const activeFlights = flights.filter((f) => {
        const status = f.status.toLowerCase().replace(/[_-]/g, ' ');
        return ['activo', 'on time'].includes(status);
      });
      const shuffled = [...activeFlights].sort(() => 0.5 - Math.random());
      return shuffled.slice(0, 4);
    }

    return flights.filter((f) => {
      const matchesSearch = `${f.code} ${f.origin} ${f.destination} ${f.status}`
        .toLowerCase()
        .includes(search.toLowerCase());

      const matchesOrigin = filters.origin
        ? f.origin.toLowerCase().includes(filters.origin.toLowerCase())
        : true;

      const matchesDestination = filters.destination
        ? f.destination
            .toLowerCase()
            .includes(filters.destination.toLowerCase())
        : true;

      return matchesSearch && matchesOrigin && matchesDestination;
    });
  }, [flights, search, filters, featured]);

  return (
    <div className="space-y-6">
      {!featured && (
        <FlightFilters
          filters={filters}
          setFilters={setFilters}
          search={search}
          setSearch={setSearch}
        />
      )}

      {loading && (
        <div className="flex flex-col items-center gap-2">
          <Loader />
          <p className="text-blue-500 font-medium">Cargando vuelos...</p>
        </div>
      )}
      {error && <p className="text-red-600 font-medium">{error}</p>}

      <ul
        className={`grid grid-cols-1 md:grid-cols-2 ${
          featured ? 'lg:grid-cols-4' : 'lg:grid-cols-3'
        } gap-6`}
      >
        {filteredFlights.length > 0
          ? filteredFlights.map((f) => (
              <li key={f.id}>
                <FlightCard flight={f} />
              </li>
            ))
          : !loading && (
              <p className="italic text-gray-500 dark:text-gray-400">
                No se encontraron vuelos
              </p>
            )}
      </ul>
    </div>
  );
}
